  const updatedRoom = await Room.findByIdAndUpdate(
    req.params.id,
    req.body,
    { new: true }
  );
  res.send(updatedRoom);
});

// DELETE a room
app.delete('/rooms/:id', async (req, res) => {
  await Room.findByIdAndDelete(req.params.id);
  res.status(204).send();
});

app.listen(3000, () => console.log('Server running on port 3000'));
